import { useState, useRef, useEffect, useCallback } from "react";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Sheet, SheetContent, SheetHeader, SheetTitle } from "@/components/ui/sheet";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import { useToast } from "@/hooks/use-toast";
import { useSubscription } from "@/hooks/use-subscription";
import UsageLimitBanner from "@/components/subscription/UsageLimitBanner";
import { 
  Lightbulb, 
  Users, 
  FileText, 
  BarChart3, 
  TrendingUp, 
  Send, 
  MessageSquare, 
  Plus, 
  Search, 
  Paperclip,
  Trash2,
  PanelLeftClose,
  PanelLeft,
  Loader2,
  Sparkles,
  ArrowRight,
  FolderOpen,
  ChevronRight,
  Image,
  FileUp,
  X,
  Mic,
  FileSignature,
  Receipt,
  Copy,
  Check,
  Pencil,
  RotateCcw,
  Brain,
  MoreVertical,
  Pin,
  PinOff,
} from "lucide-react";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
  DropdownMenuSeparator,
} from "@/components/ui/dropdown-menu";
import { CreateProjectDialog } from "@/components/kira/CreateProjectDialog";
import { ProjectDetailSheet } from "@/components/kira/ProjectDetailSheet";
import { ProjectsView } from "@/components/kira/ProjectsView";
import { VoiceChatDialog } from "@/components/kira/VoiceChatDialog";
import CreateContractDialog from "@/components/studio/CreateContractDialog";
import CreateInvoiceDialog from "@/components/studio/CreateInvoiceDialog";
import { ApproveActionDialog } from "@/components/kira/ApproveActionDialog";
import { KiraMemoryPanel } from "@/components/kira/KiraMemoryPanel";
import { motion, AnimatePresence } from "framer-motion";


interface ChatHistory {
  id: string;
  title: string;
  timestamp: Date;
  project_id?: string | null;
  pinned?: boolean;
}

interface Message {
  role: "user" | "assistant";
  content: string;
  file?: string;
  timestamp?: Date;
}

interface Project {
  id: string;
  name: string;
  description: string | null;
  custom_instructions: string | null;
  created_at: string;
  updated_at: string;
}

input.old_string:
interface ChatHistory {
  id: string;
  title: string;
  timestamp: Date;
  project_id?: string | null;
  pinned?: boolean;
}

input.new_string:
interface ChatHistory {
  id: string;
  title: string;
  timestamp: Date;
  project_id?: string | null;
  pinned?: boolean;
}

// ── Desktop chat item with 3-dot context menu ──
interface DesktopChatItemProps {
  chat: ChatHistory;
  isActive: boolean;
  isRenaming: boolean;
  renameValue: string;
  indent?: boolean;
  onSelect: () => void;
  onRenameChange: (v: string) => void;
  onRenameSubmit: () => void;
  onRenameCancel: () => void;
  onStartRename: () => void;
  onPin: () => void;
  onDelete: () => void;
}

function DesktopChatItem({
  chat, isActive, isRenaming, renameValue, indent = false,
  onSelect, onRenameChange, onRenameSubmit, onRenameCancel, onStartRename, onPin, onDelete,
}: DesktopChatItemProps) {
  return (
    <div
      onClick={() => { if (!isRenaming) onSelect(); }}
      className={`group flex items-center gap-2 ${indent ? 'p-2 pl-7' : 'p-2.5'} rounded-lg cursor-pointer transition-all ${
        isActive ? 'bg-bronze/10 text-foreground' : 'text-muted-foreground hover:bg-muted/50 hover:text-foreground'
      }`}
    >
      <MessageSquare className={`w-${indent ? '3.5' : '4'} h-${indent ? '3.5' : '4'} flex-shrink-0 ${isActive ? 'text-bronze' : ''}`} />

      {isRenaming ? (
        <input
          autoFocus
          value={renameValue}
          onChange={(e) => onRenameChange(e.target.value)}
          onKeyDown={(e) => {
            if (e.key === 'Enter') onRenameSubmit();
            if (e.key === 'Escape') onRenameCancel();
          }}
          onBlur={onRenameSubmit}
          onClick={(e) => e.stopPropagation()}
          className="flex-1 bg-transparent text-sm outline-none border-b border-bronze/50 focus:border-bronze text-foreground min-w-0"
        />
      ) : (
        <span className="flex-1 text-sm truncate">{chat.title}</span>
      )}

      <DropdownMenu>
        <DropdownMenuTrigger asChild onClick={(e) => e.stopPropagation()}>
          <button className="opacity-0 group-hover:opacity-100 p-1 rounded hover:bg-muted/80 transition-all flex-shrink-0">
            <MoreVertical className="w-3.5 h-3.5" />
          </button>
        </DropdownMenuTrigger>
        <DropdownMenuContent align="end" className="w-44">
          <DropdownMenuItem
            onClick={(e) => { e.stopPropagation(); onPin(); }}
            className="gap-2 cursor-pointer"
          >
            {chat.pinned ? <PinOff className="w-3.5 h-3.5" /> : <Pin className="w-3.5 h-3.5" />}
            {chat.pinned ? 'Unpin' : 'Pin'}
          </DropdownMenuItem>
          <DropdownMenuItem
            onClick={(e) => { e.stopPropagation(); onStartRename(); }}
            className="gap-2 cursor-pointer"
          >
            <Pencil className="w-3.5 h-3.5" />
            Rename
          </DropdownMenuItem>
          <DropdownMenuSeparator />
          <DropdownMenuItem
            onClick={(e) => { e.stopPropagation(); onDelete(); }}
            className="gap-2 cursor-pointer text-destructive focus:text-destructive"
          >
            <Trash2 className="w-3.5 h-3.5" />
            Delete
          </DropdownMenuItem>
        </DropdownMenuContent>
      </DropdownMenu>
    </div>
  );
}

// ── Mobile chat item with long-press ──
interface MobileChatItemProps {
  chat: ChatHistory;
  isActive: boolean;
  isRenaming: boolean;
  renameValue: string;
  onSelect: () => void;
  onRenameChange: (v: string) => void;
  onRenameSubmit: () => void;
  onRenameCancel: () => void;
  onLongPress: () => void;
  onLongPressStart: () => void;
  onLongPressEnd: () => void;
}

function MobileChatItem({
  chat, isActive, isRenaming, renameValue,
  onSelect, onRenameChange, onRenameSubmit, onRenameCancel,
  onLongPress: _onLongPress, onLongPressStart, onLongPressEnd,
}: MobileChatItemProps) {
  return (
    <div
      onClick={() => { if (!isRenaming) onSelect(); }}
      onTouchStart={onLongPressStart}
      onTouchEnd={onLongPressEnd}
      onTouchMove={onLongPressEnd}
      onContextMenu={(e) => { e.preventDefault(); _onLongPress(); }}
      className={`flex items-center gap-2 p-2.5 rounded-lg cursor-pointer transition-all select-none ${
        isActive ? 'bg-bronze/10' : 'hover:bg-muted/50'
      }`}
    >
      <MessageSquare className={`w-4 h-4 flex-shrink-0 ${isActive ? 'text-bronze' : 'text-muted-foreground'}`} />

      {isRenaming ? (
        <input
          autoFocus
          value={renameValue}
          onChange={(e) => onRenameChange(e.target.value)}
          onKeyDown={(e) => {
            if (e.key === 'Enter') onRenameSubmit();
            if (e.key === 'Escape') onRenameCancel();
          }}
          onBlur={onRenameSubmit}
          onClick={(e) => e.stopPropagation()}
          className="flex-1 bg-transparent text-sm outline-none border-b border-bronze/50 focus:border-bronze text-foreground min-w-0"
        />
      ) : (
        <span className="flex-1 text-sm truncate">{chat.title}</span>
      )}

      {chat.pinned && <Pin className="w-3 h-3 text-muted-foreground/60 flex-shrink-0" />}
    </div>
  );
}

