      <button
        onClick={(e) => { e.stopPropagation(); onLongPress(); }}
        className="p-1 rounded flex-shrink-0 text-muted-foreground/50 hover:text-muted-foreground hover:bg-muted/80 transition-all"
      >
        <MoreVertical className="w-3.5 h-3.5" />
      </button>
    </div>
  );
}

