const THINKING_STATES = [
  "Analyzing your request...",
  "Checking your Crevia data...",
  "Formulating response...",
];

function ThinkingIndicator() {
  const [stateIdx, setStateIdx] = useState(0);
  useEffect(() => {
    const id = setInterval(() => setStateIdx(i => (i + 1) % THINKING_STATES.length), 1500);
    return () => clearInterval(id);
  }, []);
  return (
    <motion.div
      initial={{ opacity: 0, y: 8 }}
      animate={{ opacity: 1, y: 0 }}
      exit={{ opacity: 0, y: -4 }}
      transition={{ duration: 0.3 }}
      className="flex gap-3"
    >
      <div className="bg-muted rounded-2xl rounded-tl-md px-4 py-3">
        <div className="flex items-center gap-2.5">
          <div className="flex gap-1">
            {[0, 1, 2].map(i => (
              <motion.span
                key={i}
                className="block w-1.5 h-1.5 rounded-full bg-bronze"
                animate={{ opacity: [0.3, 1, 0.3] }}
                transition={{ duration: 1.2, repeat: Infinity, delay: i * 0.2 }}
              />
            ))}
          </div>
          <AnimatePresence mode="wait">
            <motion.span
              key={stateIdx}
              initial={{ opacity: 0, y: 4 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -4 }}
              transition={{ duration: 0.2 }}
              className="text-sm text-muted-foreground"
            >
              {THINKING_STATES[stateIdx]}
            </motion.span>
          </AnimatePresence>
        </div>
      </div>
    </motion.div>
  );
}

function StreamingCursor() {
  return (
    <motion.span
      animate={{ opacity: [1, 0] }}
      transition={{ duration: 0.5, repeat: Infinity, repeatType: "reverse" }}
      className="inline-block w-0.5 h-4 bg-foreground/70 ml-0.5 align-middle"
    />
  );
}

interface Message {
  role: "user" | "assistant";
  content: string;
  file?: string;
  timestamp?: Date;
}

interface Project {
  id: string;
  name: string;
